final:
module JK_Latch (
    input J,
    input K,
    input clk,
    output reg Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (J == 1 && K == 0)
            Q <= 1;         // Set
        else if (J == 0 && K == 1)
            Q <= 0;         // Reset
        else if (J == 1 && K == 1)
            Q <= ~Q;        // Toggle
        // else retain previous state
    end
endmodule
